            0x1319_8a2e,
            0x0370_7344,
        ),
        PhiloxCoordinate::new(0x0123_4567_89ab_cdef, 17, 23, 42, 5),
    ];
    let expected = coordinates
        .iter()
        .map(|coordinate| {
            draw_u32x4(
