        let lhs = input_number(lhs)?;
        let rhs = input_number(rhs)?;
        return Ok(InputScalar::Real(match expr {
            Expr::Add { .. } => lhs + rhs,
            Expr::Sub { .. } => lhs - rhs,
            Expr::Mul { .. } => lhs * rhs,
