   346	    let next_inputs = match state
   347	        .prepared_snapshot()
   348	        .map_err(TickError::from)
   349	        .and_then(|prepared| build_next_inputs(model, &prepared, params))
   350	    {
   351	        Ok(inputs) => inputs,
   352	        Err(error) => {
   353	            state.discard_writes();
   354	            return Err(error);
   355	        }
   356	    };
   357	    if let Err(error) = state.commit() {
   358	        state.discard_writes();
   359	        return Err(error.into());
   360	    }
   361	    state.replace_inputs(next_inputs);
   362	    // Observation is deliberately evaluated only after commit and receives an
   363	    // immutable store. It cannot consume RNG coordinates, stage writes, or
   364	    // influence conflict resolution or scheduling.
   365	    let views = evaluate_views(model, state, params)?;
   366	
   367	    let mut fired = model
   368	        .transitions()
   369	        .iter()
   370	        .map(|transition| (transition.rule_id, 0))
   371	        .collect::<Vec<_>>();
   372	    let mut fired_per_box = Vec::with_capacity(box_outcomes.len());
   373	    let mut deferred_per_resource_table = Vec::new();
   374	    let mut fired_per_resource_table = Vec::new();
   375	    let mut aggregate_builds = 0;
   376	    let qualify = model.model().boxes.len() > 1;
   377	    for (box_index, outcome) in box_outcomes.into_iter().enumerate() {
   378	        let model_box = &model.model().boxes[box_index];
   379	        for (rule_id, count) in &outcome.fired {
   380	            fired[*rule_id as usize].1 = *count;
   381	        }
   382	        fired_per_box.push((model_box.name.clone(), outcome.fired));
   383	        aggregate_builds += outcome.aggregate_builds;
   384	        for (table_index, count) in outcome.deferred.into_iter().enumerate() {
   385	            let name = report_table_name(model_box, table_index, qualify);
   386	            if count != 0 {
   387	                deferred_per_resource_table.push((name.clone(), count));
   388	            }
   389	            fired_per_resource_table.push((name, outcome.fired_per_resource_table[table_index]));
   390	        }
   391	    }
   392	
   393	    Ok(TickOutcome {
   394	        report: TickReport {
   395	            tick,
   396	            views,
   397	            fired,
   398	            fired_per_box,
   399	            deferred_per_resource_table,
   400	            aggregate_builds,
   401	        },
   402	        fired_per_resource_table,
   403	    })
   404	}
