   578	                        TickError::Evaluation(format!("summary '{name}' integer sum overflowed"))
   579	                    })?;
   580	                }
   581	                Ok(ObservationValue::Int(total))
   582	            }
   583	            ObservationValue::Real(_) => {
   584	                let mut total = 0.0;
   585	                for &(_, value) in values {
   586	                    let ObservationValue::Real(value) = value else {
   587	                        return Err(summary_type_mismatch(name));
   588	                    };
   589	                    total += value;
   590	                }
   591	                Ok(ObservationValue::Real(total))
   592	            }
   593	        },
   594	        SummaryReduce::Min | SummaryReduce::Max => {
   595	            let mut result = first_value;
   596	            for &(_, value) in &values[1..] {
   597	                let ordering = observation_cmp(value, result)?;
   598	                if (reduce == SummaryReduce::Min && ordering == Ordering::Less)
   599	                    || (reduce == SummaryReduce::Max && ordering == Ordering::Greater)
