   609	fn observation_cmp(left: ObservationValue, right: ObservationValue) -> Result<Ordering, TickError> {
   610	    match (left, right) {
   611	        (ObservationValue::Int(left), ObservationValue::Int(right)) => Ok(left.cmp(&right)),
   612	        (ObservationValue::Real(left), ObservationValue::Real(right)) => Ok(left.total_cmp(&right)),
   613	        _ => Err(TickError::Evaluation(
   614	            "observation values changed numeric type across ticks".to_owned(),
   615	        )),
   616	    }
   617	}
