   633	fn stage_box(
   634	    model: &ValidatedModel,
   635	    box_index: usize,
   636	    snapshot: &Snapshot<'_>,
   637	    params: &ParamEnv,
   638	    seed: u64,
   639	    tick: u32,
   640	) -> Result<BoxOutcome, TickError> {
   641	    let model_box = &model.model().boxes[box_index];
   642	    let transitions: Vec<_> = model
   643	        .transitions()
   644	        .iter()
   645	        .filter(|transition| transition.box_index == box_index)
   646	        .collect();
   647	    let mut cache = AggCache::new(model, snapshot, params);
   648	    let mut candidates = Vec::new();
   649	    for validated in &transitions {
   650	        let transition = &model_box.transitions[validated.transition_index];
   651	        let table_index = model_box
   652	            .tables
   653	            .iter()
   654	            .position(|table| table.name == transition.table)
   655	            .expect("validated transition table disappeared");
   656	        let table = EvalTable::new(model, &model_box.name, &transition.table)?;
   657	        let guards = match eval_column(&transition.guard, table, snapshot, params, &mut cache)? {
   658	            ValueColumn::Bool(values) => values,
   659	            other => return Err(runtime_type("transition guard", &other)),
   660	        };
   661	        let hazards = match eval_column(&transition.hazard, table, snapshot, params, &mut cache)? {
   662	            ValueColumn::Real(values) => values,
   663	            other => return Err(runtime_type("transition hazard", &other)),
   664	        };
   665	        let mut claim_columns = Vec::with_capacity(transition.contests.len());
   666	        for claim in &transition.contests {
   667	            let resources =
   668	                eval_typed_ref_column(&claim.resource, table, snapshot, params, &mut cache)?;
   669	            let resource_table_index = model_box
   670	                .tables
   671	                .iter()
   672	                .position(|schema| schema.name == resources.target_table)
   673	                .expect("validated Ref target table disappeared");
   674	            let ordering = match &claim.ordering {
   675	                ClaimOrdering::RaceTime => None,
   676	                ClaimOrdering::Key { expr } => {
   677	                    Some(eval_column(expr, table, snapshot, params, &mut cache)?)
   678	                }
   679	            };
   680	            claim_columns.push((resource_table_index, resources.values, ordering, claim));
   681	        }
   682	        for (row, (guard, lambda)) in guards.into_iter().zip(hazards).enumerate() {
   683	            if !guard || lambda.partial_cmp(&0.0) != Some(Ordering::Greater) {
   684	                continue;
   685	            }
   686	            let entity_id = u32::try_from(row).map_err(|_| TickError::EntityIdOverflow {
   687	                rule_id: validated.rule_id,
   688	                row,
   689	            })?;
   690	            let race_time = exp_f64(seed, tick, validated.rule_id, entity_id, 0, lambda);
   691	            if race_time.partial_cmp(&model.model().dt) != Some(Ordering::Less) {
   692	                continue;
   693	            }
   694	            let mut claims = Vec::with_capacity(claim_columns.len());
   695	            for (resource_table, resources, key_column, claim) in &claim_columns {
   696	                let ordering = match (&claim.ordering, key_column) {
   697	                    (ClaimOrdering::RaceTime, None) => OrderingValue::RaceTime(race_time),
   698	                    (ClaimOrdering::Key { expr }, Some(column)) => {
   699	                        key_at(column, expr, table_index, model_box, row)?
   700	                    }
   701	                    _ => unreachable!("claim ordering column construction is exhaustive"),
   702	                };
   703	                claims.push(CandidateClaim {
   704	                    table_index: *resource_table,
   705	                    resource_row: resources[row],
   706	                    ordering,
   707	                });
   708	            }
   709	            candidates.push(Candidate {
   710	                rule_id: validated.rule_id,
   711	                table_index,
   712	                entity_id,
   713	                row,
   714	                claims,
   715	            });
   716	        }
   717	    }
   718	    let resolution = resolve_claims(&candidates, model_box.tables.len(), model_box)?;
   719	    let mut pending = Vec::new();
   720	    for validated in &transitions {
   721	        let transition = &model_box.transitions[validated.transition_index];
   722	        let winner_indices: Vec<usize> = candidates
   723	            .iter()
   724	            .enumerate()
   725	            .filter(|(index, candidate)| {
   726	                candidate.rule_id == validated.rule_id && resolution.fires[*index]
   727	            })
   728	            .map(|(index, _)| index)
   729	            .collect();
   730	        if winner_indices.is_empty() {
   731	            continue;
   732	        }
   733	        let table = EvalTable::new(model, &model_box.name, &transition.table)?;
   734	        let table_index = candidates[winner_indices[0]].table_index;
   735	        let schema = &model_box.tables[table_index];
