  1227	fn eval_arithmetic(
  1228	    operation: Arithmetic,
  1229	    lhs: &Expr,
  1230	    rhs: &Expr,
  1231	    table: EvalTable<'_>,
  1232	    row_attrs: &[Attr],
  1233	    snapshot: &Snapshot<'_>,
  1234	    params: &ParamEnv,
  1235	    cache: &mut AggCache<'_, '_>,
  1236	) -> Result<InternalColumn, EvalError> {
  1237	    let lhs = eval_expr(lhs, table, row_attrs, snapshot, params, cache, None)?;
  1238	    let rhs = eval_expr(rhs, table, row_attrs, snapshot, params, cache, None)?;
  1239	    if matches!(operation, Arithmetic::Div)
  1240	        || matches!(lhs, InternalColumn::Real(_))
  1241	        || matches!(rhs, InternalColumn::Real(_))
  1242	    {
  1243	        let lhs = numeric_as_real(&lhs)?;
  1244	        let rhs = numeric_as_real(&rhs)?;
  1245	        return Ok(InternalColumn::Real(
  1246	            lhs.into_iter()
  1247	                .zip(rhs)
  1248	                .map(|(lhs, rhs)| match operation {
  1249	                    Arithmetic::Add => lhs + rhs,
  1250	                    Arithmetic::Sub => lhs - rhs,
  1251	                    Arithmetic::Mul => lhs * rhs,
  1252	                    Arithmetic::Div => lhs / rhs,
  1253	                })
  1254	                .collect(),
  1255	        ));
  1256	    }
  1257	    let (InternalColumn::Int(lhs), InternalColumn::Int(rhs)) = (lhs, rhs) else {
  1258	        return Err(EvalError::new("arithmetic operands are not numeric"));
  1259	    };
  1260	    let values = lhs
  1261	        .into_iter()
  1262	        .zip(rhs)
  1263	        .enumerate()
  1264	        .map(|(row, (lhs, rhs))| {
  1265	            let value = match operation {
  1266	                Arithmetic::Add => lhs.checked_add(rhs),
  1267	                Arithmetic::Sub => lhs.checked_sub(rhs),
  1268	                Arithmetic::Mul => lhs.checked_mul(rhs),
  1269	                Arithmetic::Div => unreachable!("division promotes to Real"),
  1270	            };
  1271	            value.ok_or_else(|| EvalError::new(format!("integer arithmetic overflow at row {row}")))
  1272	        })
  1273	        .collect::<Result<Vec<_>, _>>()?;
  1274	    Ok(InternalColumn::Int(values))
  1275	}
