  1324	fn equal_columns(lhs: &InternalColumn, rhs: &InternalColumn) -> Result<Vec<bool>, EvalError> {
  1325	    if let (InternalColumn::Int(lhs), InternalColumn::Int(rhs)) = (lhs, rhs) {
  1326	        return Ok(lhs.iter().zip(rhs).map(|(lhs, rhs)| lhs == rhs).collect());
  1327	    }
  1328	    if matches!(lhs, InternalColumn::Real(_) | InternalColumn::Int(_))
  1329	        && matches!(rhs, InternalColumn::Real(_) | InternalColumn::Int(_))
  1330	    {
  1331	        return Ok(numeric_as_real(lhs)?
  1332	            .into_iter()
  1333	            .zip(numeric_as_real(rhs)?)
  1334	            .map(|(lhs, rhs)| lhs == rhs)
  1335	            .collect());
  1336	    }
  1337	    let values = match (lhs, rhs) {
  1338	        (InternalColumn::Bool(lhs), InternalColumn::Bool(rhs)) => {
  1339	            lhs.iter().zip(rhs).map(|(lhs, rhs)| lhs == rhs).collect()
  1340	        }
  1341	        (InternalColumn::Enum(lhs), InternalColumn::Enum(rhs)) => {
  1342	            lhs.iter().zip(rhs).map(|(lhs, rhs)| lhs == rhs).collect()
  1343	        }
  1344	        (InternalColumn::Ref(lhs), InternalColumn::Ref(rhs)) => {
  1345	            lhs.iter().zip(rhs).map(|(lhs, rhs)| lhs == rhs).collect()
  1346	        }
  1347	        _ => return Err(EvalError::new("equality operands have incompatible types")),
  1348	    };
  1349	    Ok(values)
  1350	}
