382	    pub fn run(&mut self, ticks: u32) -> Result<CudaRunResult, CudaError> {
383	        let mut per_tick_state_hashes = if self.hash_mode == HashMode::EveryTick {
384	            Vec::with_capacity(ticks as usize)
385	        } else {
386	            Vec::new()
387	        };
388	        for _ in 0..ticks {
389	            self.execute_tick()?;
390	            if self.hash_mode == HashMode::EveryTick {
391	                per_tick_state_hashes.push(self.download_hash()?);
392	            }
393	        }
394	        let final_state_hash = match per_tick_state_hashes.last() {
395	            Some(hash) => *hash,
396	            None => self.download_hash()?,
397	        };
398	        Ok(CudaRunResult {
399	            final_state_hash,
400	            per_tick_state_hashes,
401	        })
402	    }
