 219	    fn collect_all(&mut self) -> Result<(), CudaError> {
 220	        for validated in self.model.transitions() {
 221	            let box_index = validated.box_index;
 222	            let transition =
 223	                &self.model.model().boxes[box_index].transitions[validated.transition_index];
 224	            let table_index = self.table_index(box_index, &transition.table)?;
 225	            self.collect_expr(
 226	                box_index,
 227	                table_index,
 228	                &transition.guard,
 229	                AggUse::Schedule(validated.rule_id),
 230	            )?;
 231	            self.collect_expr(
 232	                box_index,
 233	                table_index,
 234	                &transition.hazard,
 235	                AggUse::Schedule(validated.rule_id),
 236	            )?;
 237	            for effect in &transition.effects {
 238	                let Effect::SetAttr { value, .. } = effect;
 239	                self.collect_expr(
 240	                    box_index,
 241	                    table_index,
 242	                    value,
 243	                    AggUse::Effect(validated.rule_id),
 244	                )?;
 245	            }
 246	            for claim in &transition.contests {
 247	                self.collect_expr(
 248	                    box_index,
 249	                    table_index,
 250	                    &claim.resource,
 251	                    AggUse::Schedule(validated.rule_id),
 252	                )?;
 253	                if let ClaimOrdering::Key { expr } = &claim.ordering {
 254	                    self.collect_expr(
 255	                        box_index,
 256	                        table_index,
 257	                        expr,
 258	                        AggUse::Schedule(validated.rule_id),
 259	                    )?;
 260	                }
 261	            }
 262	        }
 263	
 264	        // Only wired outputs are observable and evaluated by the CPU oracle.
 265	        for wire in &self.model.model().wires {
 266	            let box_index = self
 267	                .model
 268	                .model()
 269	                .boxes
 270	                .iter()
 271	                .position(|model_box| model_box.name == wire.from.r#box)
 272	                .expect("validated output box is indexed");
 273	            let model_box = &self.model.model().boxes[box_index];
 274	            let output = model_box
 275	                .outputs
 276	                .iter()
 277	                .find(|output| output.name == wire.from.port)
 278	                .expect("validated output is indexed");
 279	            let sembla_ir::OutputBuilder::PerTable { table, fields } = &output.builder;
 280	            let table_index = self.table_index(box_index, table)?;
 281	            for field in fields {
 282	                if let Some(filter) = &field.filter {
 283	                    self.collect_expr(box_index, table_index, filter, AggUse::Output)?;
 284	                }
 285	                if let AggOp::Sum { value } = &field.op {
 286	                    self.collect_expr(box_index, table_index, value, AggUse::Output)?;
 287	                }
 288	            }
 289	        }
 290	        Ok(())
 291	    }
