 293	    fn collect_expr(
 294	        &mut self,
 295	        box_index: usize,
 296	        query_table_index: usize,
 297	        expr: &Expr,
 298	        usage: AggUse,
 299	    ) -> Result<(), CudaError> {
 300	        match expr {
 301	            Expr::Add { lhs, rhs }
 302	            | Expr::Sub { lhs, rhs }
 303	            | Expr::Mul { lhs, rhs }
 304	            | Expr::Div { lhs, rhs }
 305	            | Expr::Eq { lhs, rhs }
 306	            | Expr::Ne { lhs, rhs }
 307	            | Expr::Lt { lhs, rhs }
 308	            | Expr::Le { lhs, rhs }
 309	            | Expr::Gt { lhs, rhs }
 310	            | Expr::Ge { lhs, rhs }
 311	            | Expr::And { lhs, rhs }
 312	            | Expr::Or { lhs, rhs } => {
 313	                self.collect_expr(box_index, query_table_index, lhs, usage)?;
 314	                self.collect_expr(box_index, query_table_index, rhs, usage)?;
 315	            }
 316	            Expr::Not { expr } => self.collect_expr(box_index, query_table_index, expr, usage)?,
 317	            Expr::Input { port, agg } => {
 318	                if let Some(filter) = &agg.filter {
 319	                    Self::validate_input_expr(filter)?;
 320	                }
 321	                if let AggOp::Sum { value } = &agg.op {
 322	                    Self::validate_input_expr(value)?;
 323	                }
 324	                let key = format!("{box_index}:{port}:{agg:?}");
 325	                if !self.inputs.iter().any(|entry| entry.key == key) {
 326	                    let port_index = self.port_index(box_index, port)?;
 327	                    let ty = match &agg.op {
 328	                        AggOp::Count => Ty::Int,
 329	                        AggOp::Sum { value } => self.infer(
 330	                            value,
 331	                            Rows::Input {
 332	                                box_index,
 333	                                port_index,
 334	                            },
 335	                            None,
 336	                        )?,
 337	                    };
 338	                    self.inputs.push(InputSpec {
 339	                        key,
 340	                        box_index,
 341	                        port_index,
 342	                        agg: agg.clone(),
 343	                        ty,
 344	                    });
 345	                }
 346	            }
 347	            Expr::Agg {
 348	                op,
 349	                table,
 350	                on,
 351	                filter,
 352	            } => {
 353	                let target_table_index = self.table_index(box_index, table)?;
 354	                self.collect_expr(box_index, target_table_index, filter, usage)?;
 355	                if let AggOp::Sum { value } = op {
 356	                    self.collect_expr(box_index, target_table_index, value, usage)?;
 357	                }
 358	                let key = format!("{box_index}:{query_table_index}:{expr:?}");
 359	                if let Some(existing) = self.aggs.iter_mut().find(|entry| entry.key == key) {
 360	                    existing.record_use(usage);
 361	                } else {
 362	                    let query_table =
 363	                        &self.model.model().boxes[box_index].tables[query_table_index];
 364	                    let target_table =
 365	                        &self.model.model().boxes[box_index].tables[target_table_index];
 610	                    ty,
 611	                )
 612	            }
 613	            Expr::SelfAttr { name } => self.render_attr(rows, name, state_name, row_name)?,
 614	            Expr::Add { lhs, rhs } | Expr::Sub { lhs, rhs } | Expr::Mul { lhs, rhs } => {
 615	                let (left, left_ty) = self.render(lhs, rows, None, state_name, row_name)?;
 616	                let (right, right_ty) = self.render(rhs, rows, None, state_name, row_name)?;
 617	                let ty = if left_ty == Ty::Real || right_ty == Ty::Real {
 618	                    Ty::Real
 619	                } else {
 620	                    Ty::Int
 621	                };
 622	                if ty == Ty::Int {
 623	                    let helper = match expr {
 624	                        Expr::Add { .. } => "sembla_add_i64",
 625	                        Expr::Sub { .. } => "sembla_sub_i64",
 626	                        Expr::Mul { .. } => "sembla_mul_i64",
 627	                        _ => unreachable!(),
 628	                    };
 629	                    (format!("{helper}({left}, {right}, error)"), ty)
 630	                } else {
 631	                    let operator = match expr {
 632	                        Expr::Add { .. } => "+",
 633	                        Expr::Sub { .. } => "-",
 634	                        Expr::Mul { .. } => "*",
 635	                        _ => unreachable!(),
 636	                    };
 637	                    (
 638	                        format!("((double)({left}) {operator} (double)({right}))"),
 639	                        ty,
 640	                    )
 641	                }
 642	            }
 643	            Expr::Div { lhs, rhs } => {
 644	                let (left, _) = self.render(lhs, rows, None, state_name, row_name)?;
 645	                let (right, _) = self.render(rhs, rows, None, state_name, row_name)?;
 646	                (format!("((double)({left}) / (double)({right}))"), Ty::Real)
 647	            }
 648	            Expr::Eq { lhs, rhs }
 649	            | Expr::Ne { lhs, rhs }
 650	            | Expr::Lt { lhs, rhs }
 651	            | Expr::Le { lhs, rhs }
 652	            | Expr::Gt { lhs, rhs }
 653	            | Expr::Ge { lhs, rhs } => {
 654	                let left_hint = self.infer(lhs, rows, None).ok();
 655	                let right_hint = self.infer(rhs, rows, left_hint.as_ref()).ok();
 656	                let (left, left_ty) =
 657	                    self.render(lhs, rows, right_hint.as_ref(), state_name, row_name)?;
 658	                let (right, right_ty) =
 659	                    self.render(rhs, rows, Some(&left_ty), state_name, row_name)?;
 660	                let input_ordering = matches!(rows, Rows::Input { .. })
 661	                    && matches!(
 662	                        expr,
 663	                        Expr::Lt { .. } | Expr::Le { .. } | Expr::Gt { .. } | Expr::Ge { .. }
 664	                    );
 665	                let promote_numeric = left_ty.numeric()
 666	                    && right_ty.numeric()
 667	                    && (left_ty == Ty::Real || right_ty == Ty::Real || input_ordering);
 668	                let left = if promote_numeric {
 669	                    format!("(double)({left})")
 670	                } else {
 671	                    left
 672	                };
 673	                let right = if promote_numeric {
 674	                    format!("(double)({right})")
 675	                } else {
 676	                    right
 677	                };
 678	                let operator = match expr {
 679	                    Expr::Eq { .. } => "==",
 680	                    Expr::Ne { .. } => "!=",
 681	                    Expr::Lt { .. } => "<",
 682	                    Expr::Le { .. } => "<=",
 683	                    Expr::Gt { .. } => ">",
 684	                    Expr::Ge { .. } => ">=",
 685	                    _ => unreachable!(),
 686	                };
 687	                (format!("(({left}) {operator} ({right}))"), Ty::Bool)
 688	            }
 689	            Expr::And { lhs, rhs } | Expr::Or { lhs, rhs } => {
 690	                let (left, _) = self.render(lhs, rows, Some(&Ty::Bool), state_name, row_name)?;
 691	                let (right, _) = self.render(rhs, rows, Some(&Ty::Bool), state_name, row_name)?;
 692	                let operator = if matches!(expr, Expr::And { .. }) {
 693	                    "&"
 694	                } else {
 695	                    "|"
 696	                };
 697	                (format!("(({left}) {operator} ({right}))"), Ty::Bool)
 698	            }
 699	            Expr::Not { expr } => {
 700	                let (value, _) = self.render(expr, rows, Some(&Ty::Bool), state_name, row_name)?;
 701	                (format!("(!({value}))"), Ty::Bool)
 702	            }
 703	            Expr::EnumIs { attr, variant } => {
 704	                let attr_decl = self.row_attr(rows, attr)?;
 705	                let AttrType::Enum { variants } = &attr_decl.ty else {
 706	                    return Err(codegen("enum_is attribute is not Enum"));
 707	                };
 708	                let index = variants
 709	                    .iter()
 710	                    .position(|item| item == variant)
 711	                    .ok_or_else(|| codegen(format!("unknown enum variant '{variant}'")))?;
 712	                let (value, _) = self.render_attr(rows, attr, state_name, row_name)?;
 713	                (format!("(({value}) == {index}U)"), Ty::Bool)
 714	            }
 715	            Expr::Input { port, agg } => {
 716	                let box_index = rows_box(rows);
 717	                let key = format!("{box_index}:{port}:{agg:?}");
 718	                let index = self
 719	                    .inputs
 720	                    .iter()
 721	                    .position(|entry| entry.key == key)
 722	                    .ok_or_else(|| codegen("input aggregate was not collected"))?;
 723	                (
 724	                    format!(
 725	                        "sembla_input_{index}(inputs, input_offsets, input_counts, params, error)"
 726	                    ),
 727	                    self.inputs[index].ty.clone(),
 728	                )
 729	            }
 730	            Expr::Agg { .. } => {
 731	                let (box_index, table_index) = rows_state(rows)?;
 732	                let key = format!("{box_index}:{table_index}:{expr:?}");
 733	                let index = self
 734	                    .aggs
 735	                    .iter()
 736	                    .position(|entry| entry.key == key)
 737	                    .ok_or_else(|| codegen("group aggregate was not collected"))?;
 738	                let spec = &self.aggs[index];
 739	                let query = &self.model.model().boxes[box_index].tables[table_index];
 740	                let attr = &query.attrs[spec.self_fk_column];
 741	                let (group, _) = self.render_attr(rows, &attr.name, state_name, row_name)?;
 742	                (
 743	                    format!(
 744	                        "(*((const {}*)(aggs + agg_offsets[{index}]) + (unsigned long long)({group})))",
 745	                        spec.ty.cuda()
 746	                    ),
 747	                    spec.ty.clone(),
 748	                )
 749	            }
 750	        };
 751	        Ok(result)
 752	    }
