 754	    fn render_attr(
 755	        &self,
 756	        rows: Rows,
 757	        name: &str,
 758	        state_name: &str,
 759	        row_name: &str,
 760	    ) -> Result<(String, Ty), CudaError> {
 761	        match rows {
 762	            Rows::State {
