 994	    fn emit_transition_kernels(&self, out: &mut String) -> Result<Vec<String>, CudaError> {
 995	        let mut names = Vec::new();
 996	        for validated in self.model.transitions() {
 997	            let transition = &self.model.model().boxes[validated.box_index].transitions
 998	                [validated.transition_index];
