1000	            let global_table = self.global_table(validated.box_index, table_index);
1001	            let name = format!("sembla_transition_{:08x}", validated.rule_id);
1002	            names.push(name.clone());
1003	            writeln!(out, "\nextern \"C\" __global__ void {name}(const unsigned char* state, const unsigned long long* column_offsets, const unsigned long long* row_counts, const unsigned char* inputs, const unsigned long long* input_offsets, const unsigned long long* input_counts, const unsigned char* params, const unsigned char* aggs, const unsigned long long* agg_offsets, const unsigned long long* candidate_offsets, unsigned long long seed, unsigned int tick, double dt, unsigned char* enabled, double* times, unsigned char* errors) {{").unwrap();
1004	            out.push_str("  unsigned long long row = (unsigned long long)blockIdx.x * blockDim.x + threadIdx.x;\n");
1005	            writeln!(out, "  if (row >= row_counts[{global_table}]) return;\n  unsigned long long candidate = candidate_offsets[{}] + row;\n  unsigned char local_error = 0; unsigned char* error = &local_error;", validated.rule_id).unwrap();
1006	            let rows = Rows::State {
1007	                box_index: validated.box_index,
1008	                table_index,
1009	            };
1010	            let guard = self
1011	                .render(&transition.guard, rows, Some(&Ty::Bool), "state", "row")?
1012	                .0;
1013	            let hazard = self
1014	                .render(&transition.hazard, rows, Some(&Ty::Real), "state", "row")?
1015	                .0;
1016	            writeln!(out, "  int guard = {guard};\n  errors[candidate * 2ULL] = local_error;\n  local_error = 0;\n  double lambda = (double)({hazard});\n  errors[candidate * 2ULL + 1ULL] = local_error;\n  double time = sembla_exp(seed, tick, {}U, (unsigned int)row, 0U, lambda);\n  times[candidate] = time;\n  enabled[candidate] = (unsigned char)(errors[candidate * 2ULL] == 0U && errors[candidate * 2ULL + 1ULL] == 0U && guard && lambda > 0.0 && time < dt);\n}}", validated.rule_id).unwrap();
1017	        }
