 298	fn execute_tick(
 299	    model: &ValidatedModel,
 300	    state: &mut StateStore,
 301	    params: &ParamEnv,
 302	    seed: u64,
 303	    tick: u32,
 304	) -> Result<TickOutcome, TickError> {
 305	    let snapshot = state.snapshot();
 306	    let mut box_outcomes = Vec::with_capacity(model.model().boxes.len());
 307	    for box_index in 0..model.model().boxes.len() {
 308	        box_outcomes.push(stage_box(model, box_index, &snapshot, params, seed, tick)?);
 309	    }
 310	
 311	    let pending: Vec<_> = box_outcomes
 312	        .iter_mut()
 313	        .flat_map(|outcome| std::mem::take(&mut outcome.pending))
 314	        .collect();
 315	    detect_double_writes(&pending, model)?;
 316	    let apply_result = {
 317	        let mut writes = state.write_buffer()?;
 318	        pending.iter().try_for_each(|write| {
 319	            let model_box = &model.model().boxes[write.box_index];
 320	            let table = &model_box.tables[write.table_index];
 321	            let attr = &table.attrs[write.attr_index];
 322	            match &write.value {
 323	                PendingValue::Real(value) => {
 324	                    writes.set_real(&model_box.name, &table.name, &attr.name, write.row, *value)
 325	                }
 326	                PendingValue::Int(value) => {
 327	                    writes.set_int(&model_box.name, &table.name, &attr.name, write.row, *value)
 328	                }
 329	                PendingValue::Enum(value) => {
 330	                    writes.set_enum(&model_box.name, &table.name, &attr.name, write.row, *value)
 331	                }
 332	                PendingValue::Ref(value) => {
 333	                    writes.set_ref(&model_box.name, &table.name, &attr.name, write.row, *value)
 334	                }
 335	            }
 336	        })
 337	    };
 338	    if let Err(error) = apply_result {
 339	        state.discard_writes();
 340	        return Err(error.into());
 341	    }
 342	    // Moore-machine outputs observe the prospective new state, but output
 343	    // construction is fallible. Build every delivered table before commit so
 344	    // an overflow or evaluation error leaves both old state and old inputs
 345	    // unchanged.
 346	    let next_inputs = match state
 347	        .prepared_snapshot()
 348	        .map_err(TickError::from)
 349	        .and_then(|prepared| build_next_inputs(model, &prepared, params))
 350	    {
 351	        Ok(inputs) => inputs,
 352	        Err(error) => {
 353	            state.discard_writes();
 354	            return Err(error);
 355	        }
 356	    };
 357	    if let Err(error) = state.commit() {
 358	        state.discard_writes();
 359	        return Err(error.into());
 360	    }
 361	    state.replace_inputs(next_inputs);
 362	    // Observation is deliberately evaluated only after commit and receives an
 363	    // immutable store. It cannot consume RNG coordinates, stage writes, or
 364	    // influence conflict resolution or scheduling.
 365	    let views = evaluate_views(model, state, params)?;
 633	fn stage_box(
 634	    model: &ValidatedModel,
 635	    box_index: usize,
 636	    snapshot: &Snapshot<'_>,
 637	    params: &ParamEnv,
 638	    seed: u64,
 639	    tick: u32,
 640	) -> Result<BoxOutcome, TickError> {
 641	    let model_box = &model.model().boxes[box_index];
 642	    let transitions: Vec<_> = model
 643	        .transitions()
 644	        .iter()
 645	        .filter(|transition| transition.box_index == box_index)
 646	        .collect();
 647	    let mut cache = AggCache::new(model, snapshot, params);
 648	    let mut candidates = Vec::new();
 649	    for validated in &transitions {
 650	        let transition = &model_box.transitions[validated.transition_index];
 651	        let table_index = model_box
 652	            .tables
 653	            .iter()
 654	            .position(|table| table.name == transition.table)
 655	            .expect("validated transition table disappeared");
 656	        let table = EvalTable::new(model, &model_box.name, &transition.table)?;
 657	        let guards = match eval_column(&transition.guard, table, snapshot, params, &mut cache)? {
 658	            ValueColumn::Bool(values) => values,
 659	            other => return Err(runtime_type("transition guard", &other)),
 660	        };
 661	        let hazards = match eval_column(&transition.hazard, table, snapshot, params, &mut cache)? {
 662	            ValueColumn::Real(values) => values,
 663	            other => return Err(runtime_type("transition hazard", &other)),
 664	        };
 665	        let mut claim_columns = Vec::with_capacity(transition.contests.len());
 666	        for claim in &transition.contests {
 667	            let resources =
 668	                eval_typed_ref_column(&claim.resource, table, snapshot, params, &mut cache)?;
 669	            let resource_table_index = model_box
 670	                .tables
 671	                .iter()
 672	                .position(|schema| schema.name == resources.target_table)
 673	                .expect("validated Ref target table disappeared");
 674	            let ordering = match &claim.ordering {
 675	                ClaimOrdering::RaceTime => None,
 676	                ClaimOrdering::Key { expr } => {
 677	                    Some(eval_column(expr, table, snapshot, params, &mut cache)?)
 678	                }
 679	            };
 680	            claim_columns.push((resource_table_index, resources.values, ordering, claim));
 681	        }
 682	        for (row, (guard, lambda)) in guards.into_iter().zip(hazards).enumerate() {
 683	            if !guard || lambda.partial_cmp(&0.0) != Some(Ordering::Greater) {
 684	                continue;
 685	            }
 686	            let entity_id = u32::try_from(row).map_err(|_| TickError::EntityIdOverflow {
 687	                rule_id: validated.rule_id,
 688	                row,
 689	            })?;
 690	            let race_time = exp_f64(seed, tick, validated.rule_id, entity_id, 0, lambda);
 691	            if race_time.partial_cmp(&model.model().dt) != Some(Ordering::Less) {
 692	                continue;
 693	            }
 694	            let mut claims = Vec::with_capacity(claim_columns.len());
 695	            for (resource_table, resources, key_column, claim) in &claim_columns {
