 299	    model: &ValidatedModel,
 300	    state: &mut StateStore,
 301	    params: &ParamEnv,
 302	    seed: u64,
 303	    tick: u32,
 304	) -> Result<TickOutcome, TickError> {
 305	    let snapshot = state.snapshot();
 306	    let mut box_outcomes = Vec::with_capacity(model.model().boxes.len());
 307	    for box_index in 0..model.model().boxes.len() {
 308	        box_outcomes.push(stage_box(model, box_index, &snapshot, params, seed, tick)?);
 309	    }
 310	
 311	    let pending: Vec<_> = box_outcomes
 312	        .iter_mut()
 313	        .flat_map(|outcome| std::mem::take(&mut outcome.pending))
 314	        .collect();
 315	    detect_double_writes(&pending, model)?;
 316	    let apply_result = {
 317	        let mut writes = state.write_buffer()?;
 318	        pending.iter().try_for_each(|write| {
 319	            let model_box = &model.model().boxes[write.box_index];
 320	            let table = &model_box.tables[write.table_index];
 321	            let attr = &table.attrs[write.attr_index];
 322	            match &write.value {
 323	                PendingValue::Real(value) => {
 324	                    writes.set_real(&model_box.name, &table.name, &attr.name, write.row, *value)
 325	                }
 326	                PendingValue::Int(value) => {
 327	                    writes.set_int(&model_box.name, &table.name, &attr.name, write.row, *value)
 328	                }
 329	                PendingValue::Enum(value) => {
 330	                    writes.set_enum(&model_box.name, &table.name, &attr.name, write.row, *value)
 331	                }
 332	                PendingValue::Ref(value) => {
 333	                    writes.set_ref(&model_box.name, &table.name, &attr.name, write.row, *value)
 334	                }
 335	            }
 336	        })
 337	    };
 338	    if let Err(error) = apply_result {
 339	        state.discard_writes();
 340	        return Err(error.into());
 341	    }
 342	    // Moore-machine outputs observe the prospective new state, but output
 343	    // construction is fallible. Build every delivered table before commit so
 344	    // an overflow or evaluation error leaves both old state and old inputs
 345	    // unchanged.
 346	    let next_inputs = match state
 347	        .prepared_snapshot()
 348	        .map_err(TickError::from)
 349	        .and_then(|prepared| build_next_inputs(model, &prepared, params))
 350	    {
 351	        Ok(inputs) => inputs,
 352	        Err(error) => {
 353	            state.discard_writes();
 354	            return Err(error);
 355	        }
 356	    };
 357	    if let Err(error) = state.commit() {
 358	        state.discard_writes();
 359	        return Err(error.into());
 360	    }
 361	    state.replace_inputs(next_inputs);
 362	    // Observation is deliberately evaluated only after commit and receives an
 363	    // immutable store. It cannot consume RNG coordinates, stage writes, or
 364	    // influence conflict resolution or scheduling.
 365	    let views = evaluate_views(model, state, params)?;
