1018	fn write_column(bytes: &mut [u8], offset: usize, data: &ColumnData) {
1019	    match data {
1020	        ColumnData::Real(values) => {
1021	            for (row, value) in values.iter().enumerate() {
1022	                let start = offset + row * 8;
1023	                bytes[start..start + 8].copy_from_slice(&value.to_bits().to_le_bytes());
1024	            }
1025	        }
1026	        ColumnData::Int(values) => {
1027	            for (row, value) in values.iter().enumerate() {
1028	                let start = offset + row * 8;
1029	                bytes[start..start + 8].copy_from_slice(&value.to_le_bytes());
1030	            }
1031	        }
1032	        ColumnData::Enum(values) => {
1033	            for (row, value) in values.iter().enumerate() {
1034	                let start = offset + row * 2;
1035	                bytes[start..start + 2].copy_from_slice(&value.to_le_bytes());
1036	            }
1037	        }
1038	        ColumnData::Ref(values) => {
1039	            for (row, value) in values.iter().enumerate() {
1040	                let start = offset + row * 4;
1041	                bytes[start..start + 4].copy_from_slice(&value.to_le_bytes());
1042	            }
1043	        }
1044	    }
