1047	fn hash_state(
1048	    model: &ValidatedModel,
1049	    layout: &Layout,
1050	    state: &[u8],
1051	    inputs: &[u8],
1052	    input_counts: &[u64],
1053	) -> [u8; 32] {
1054	    let mut hash = Sha256::new();
1055	    if layout.ports.is_empty() {
1056	        hash.update(b"SEMBLA_STATE_V1\0");
1057	    } else {
1058	        hash.update(b"SEMBLA_STATE_V2\0");
1059	    }
1060	    update_u64(&mut hash, layout.row_counts.len());
1061	    let mut global_table_index = 0;
1062	    let mut column_index = 0;
1063	    for model_box in &model.model().boxes {
1064	        for table in &model_box.tables {
1065	            update_string(&mut hash, &model_box.name);
1066	            update_string(&mut hash, &table.name);
1067	            let rows = layout.row_counts[global_table_index] as usize;
1068	            update_u64(&mut hash, rows);
1069	            update_u64(&mut hash, table.attrs.len());
1070	            for attr in &table.attrs {
1071	                update_string(&mut hash, &attr.name);
1072	                update_packed_column(
1073	                    &mut hash,
1074	                    &attr.ty,
1075	                    state,
1076	                    layout.column_offsets[column_index] as usize,
1077	                    rows,
1078	                );
1079	                column_index += 1;
1080	            }
1081	            global_table_index += 1;
1082	        }
1083	    }
1084	    if !layout.ports.is_empty() {
1085	        update_u64(&mut hash, layout.ports.len());
1086	        let mut field = 0;
1087	        for (port_flat, (box_index, port_index)) in layout.ports.iter().copied().enumerate() {
1088	            let model_box = &model.model().boxes[box_index];
1089	            let port = &model_box.inputs[port_index];
1090	            let rows = input_counts[port_flat] as usize;
1091	            update_string(&mut hash, &model_box.name);
1092	            update_string(&mut hash, &port.name);
1093	            update_u64(&mut hash, rows);
1094	            update_u64(&mut hash, port.schema.len());
1095	            for attr in &port.schema {
1096	                update_string(&mut hash, &attr.name);
1097	                update_packed_column(
1098	                    &mut hash,
1099	                    &attr.ty,
1100	                    inputs,
1101	                    layout.input_offsets[field] as usize,
1102	                    rows,
1103	                );
1104	                field += 1;
1105	            }
1106	        }
1107	    }
1108	    hash.finalize().into()
1109	}
