 854	fn build_layout(
 855	    model: &ValidatedModel,
 856	    initial_tables: &[TableInit],
 857	    generated: &GeneratedCuda,
 858	) -> Result<Layout, CudaError> {
 859	    let mut row_counts = Vec::new();
 860	    let mut column_offsets = Vec::new();
 861	    let mut state_len = 0;
 862	    let mut ports = Vec::new();
 863	    let mut input_offsets = Vec::new();
 864	    let mut input_len = 0;
 865	    let mut write_offsets = Vec::new();
 866	    let mut owner_count = 0_usize;
 867	
 868	    for (box_index, model_box) in model.model().boxes.iter().enumerate() {
 869	        for (table_index, table) in model_box.tables.iter().enumerate() {
 870	            let initial = find_table(initial_tables, &model_box.name, &table.name)?;
 871	            row_counts.push(initial.row_count as u64);
 872	            for attr_index in 0..table.attrs.len() {
 873	                state_len = align8(state_len);
 874	                column_offsets.push(state_len as u64);
 875	                state_len = state_len
 876	                    .checked_add(
 877	                        initial
 878	                            .row_count
 879	                            .checked_mul(type_size(&table.attrs[attr_index].ty))
 880	                            .ok_or_else(|| {
 881	                                CudaError::InvalidInput("state byte size overflow".to_owned())
 882	                            })?,
 883	                    )
 884	                    .ok_or_else(|| {
 885	                        CudaError::InvalidInput("state byte size overflow".to_owned())
 886	                    })?;
 887	                write_offsets.push(owner_count as u64);
 888	                owner_count = owner_count.checked_add(initial.row_count).ok_or_else(|| {
 889	                    CudaError::InvalidInput("write-owner size overflow".to_owned())
 890	                })?;
 891	                let _ = (box_index, table_index, attr_index);
 892	            }
 893	        }
 894	        for (port_index, port) in model_box.inputs.iter().enumerate() {
 895	            ports.push((box_index, port_index));
 896	            for field_index in 0..port.schema.len() {
 897	                input_len = align8(input_len);
 898	                input_offsets.push(input_len as u64);
 899	                // v0.1 outputs are one-row aggregate tables.
 900	                input_len = input_len
 901	                    .checked_add(type_size(&port.schema[field_index].ty))
 902	                    .ok_or_else(|| {
 903	                        CudaError::InvalidInput("input byte size overflow".to_owned())
 904	                    })?;
 905	            }
 906	        }
 907	    }
 908	    state_len = state_len.max(1);
 909	    input_len = input_len.max(1);
 910	
 911	    let mut candidate_offsets = Vec::new();
 912	    let mut candidate_count = 0_usize;
 913	    for transition in model.transitions() {
 914	        candidate_offsets.push(candidate_count as u64);
 915	        let declaration =
 916	            &model.model().boxes[transition.box_index].transitions[transition.transition_index];
 917	        let table_index = model.model().boxes[transition.box_index]
 918	            .tables
 919	            .iter()
 920	            .position(|table| table.name == declaration.table)
 921	            .expect("validated transition table");
 922	        let global = global_table(model, transition.box_index, table_index);
 923	        candidate_count = candidate_count
 924	            .checked_add(row_counts[global] as usize)
 925	            .ok_or_else(|| CudaError::InvalidInput("candidate size overflow".to_owned()))?;
 926	    }
 927	
 928	    let mut aggregate_offsets = Vec::new();
 929	    let mut aggregate_len = 0_usize;
 930	    let mut aggregate_max_groups = 0_usize;
 931	    for table in &generated.aggregate_group_tables {
 932	        aggregate_max_groups = aggregate_max_groups.max(row_counts[*table] as usize);
 933	        aggregate_len = align8(aggregate_len);
 934	        aggregate_offsets.push(aggregate_len as u64);
 935	        aggregate_len = aggregate_len
 936	            .checked_add(
 937	                (row_counts[*table] as usize)
 938	                    .checked_mul(8)
 939	                    .ok_or_else(|| CudaError::InvalidInput("aggregate size overflow".to_owned()))?,
 940	            )
 941	            .ok_or_else(|| CudaError::InvalidInput("aggregate size overflow".to_owned()))?;
 942	    }
 943	
 944	    Ok(Layout {
 945	        row_counts,
 946	        column_offsets,
 947	        state_len,
 948	        ports,
 949	        input_offsets,
 950	        input_len,
 951	        candidate_offsets,
 952	        candidate_count,
 953	        aggregate_offsets,
 954	        aggregate_len: aggregate_len.max(1),
 955	        aggregate_max_groups,
 956	        write_offsets,
 957	        owner_count,
 958	    })
 959	}
