 961	fn pack_initial_state(
 962	    model: &ValidatedModel,
 963	    initial_tables: &[TableInit],
 964	    layout: &Layout,
 965	) -> Result<Vec<u8>, CudaError> {
 966	    let mut bytes = vec![0_u8; layout.state_len];
 967	    let mut column = 0;
 968	    for model_box in &model.model().boxes {
 969	        for table in &model_box.tables {
 970	            let initial = find_table(initial_tables, &model_box.name, &table.name)?;
 971	            for attr in &table.attrs {
 972	                let data = initial
 973	                    .columns
 974	                    .iter()
 975	                    .find(|entry| entry.name == attr.name)
 976	                    .ok_or_else(|| {
 977	                        CudaError::InvalidInput(format!(
 978	                            "{}.{}.{} has no initializer",
 979	                            model_box.name, table.name, attr.name
 980	                        ))
 981	                    })?;
 982	                write_column(
 983	                    &mut bytes,
 984	                    layout.column_offsets[column] as usize,
 985	                    &data.data,
 986	                );
 987	                column += 1;
 988	            }
 989	        }
 990	    }
 991	    Ok(bytes)
 992	}
