 994	fn pack_params(model: &ValidatedModel, params: &ParamEnv) -> Result<Vec<u8>, CudaError> {
 995	    let values = params.values().collect::<Vec<_>>();
 996	    if values.len() != model.model().params.len() {
 997	        return Err(CudaError::InvalidInput(
 998	            "parameter environment does not match model declarations".to_owned(),
 999	        ));
1000	    }
1001	    let mut bytes = vec![0_u8; values.len().max(1) * 8];
1002	    for (index, (name, value)) in values.into_iter().enumerate() {
1003	        if name != model.model().params[index].name {
1004	            return Err(CudaError::InvalidInput(format!(
1005	                "parameter environment entry {index} is '{name}', expected '{}'",
1006	                model.model().params[index].name
1007	            )));
1008	        }
1009	        let encoded = match value {
1010	            ParamValue::Real { value } => value.to_bits().to_le_bytes(),
1011	            ParamValue::Int { value } => value.to_le_bytes(),
1012	        };
1013	        bytes[index * 8..index * 8 + 8].copy_from_slice(&encoded);
1014	    }
1015	    Ok(bytes)
1016	}
