1111	fn update_packed_column(
1112	    hash: &mut Sha256,
1113	    ty: &AttrType,
1114	    bytes: &[u8],
1115	    offset: usize,
1116	    rows: usize,
1117	) {
1118	    let (tag, width) = match ty {
1119	        AttrType::Real => (0_u8, 8),
1120	        AttrType::Int => (1, 8),
1121	        AttrType::Enum { .. } => (2, 2),
1122	        AttrType::Ref { .. } => (3, 4),
1123	    };
1124	    hash.update([tag]);
1125	    update_u64(hash, rows);
1126	    hash.update(&bytes[offset..offset + rows * width]);
1127	}
1128	
 480	    /// Names are unnormalized UTF-8. Lengths, counts, names, type tags, and box
 481	    /// qualification make the byte stream unambiguous. Pending same-tick writes
 482	    /// are excluded because a snapshot always refers to committed old state.
 483	    ///
 484	    /// Composition uses domain `SEMBLA_STATE_V2\0`, followed by the same
 485	    /// box-major state encoding and then input tables in box/port declaration
 486	    /// order. Each input encodes its box and port names, row and column counts,
 487	    /// then named typed columns in schema order. Zero-row tick-0 inputs are
 488	    /// therefore explicit and in-flight wire values affect the digest.
 489	    pub fn state_hash(&self) -> [u8; 32] {
 490	        let mut hash = Sha256::new();
 491	        if self.inputs.is_empty() {
 492	            // Preserve PRD 0004's frozen digest for models without composition.
 493	            hash.update(b"SEMBLA_STATE_V1\0");
 494	            update_state_tables(&mut hash, &self.state.tables, true);
 495	        } else {
 496	            hash.update(b"SEMBLA_STATE_V2\0");
 497	            update_state_tables(&mut hash, &self.state.tables, true);
 498	            update_u64(&mut hash, self.inputs.len());
 499	            for input in self.inputs {
 500	                update_string(&mut hash, &input.box_name);
 501	                update_string(&mut hash, &input.port_name);
 502	                update_u64(&mut hash, input.row_count);
 503	                update_u64(&mut hash, input.schema.len());
 504	                for (attr, column) in input.schema.iter().zip(&input.columns) {
 505	                    update_string(&mut hash, &attr.name);
 506	                    update_column_data(&mut hash, column);
 507	                }
 508	            }
 509	        }
 510	        hash.finalize().into()
 511	    }
