 513	    /// Canonical hash of one table's values, independent of its containing box.
 514	    pub fn table_hash(&self, box_name: &str, table_name: &str) -> Result<[u8; 32], StateError> {
 515	        let table = find_table(self.state, box_name, table_name)?;
 516	        let mut hash = Sha256::new();
 517	        hash.update(b"SEMBLA_TABLE_V1\0");
 518	        update_string(&mut hash, &table.name);
 519	        update_u64(&mut hash, table.row_count);
 520	        update_u64(&mut hash, table.columns.len());
 521	        for column in &table.columns {
 522	            update_state_column(&mut hash, column);
 523	        }
 524	        Ok(hash.finalize().into())
 525	    }
 526	}
